WITH orders AS (
  SELECT * FROM {{ ref('stg_orders') }}
),
customers AS (
  SELECT * FROM {{ ref('stg_customers') }}
)

SELECT
  o.order_id,
  o.customer_id,
  o.created_at,
  o.amount_usd,
  o.status,
  c.email,
  c.tier            AS customer_tier,
  c.country         AS customer_country,
  c.acquisition_channel
FROM orders o
LEFT JOIN customers c USING (customer_id)

{{
  config(
    materialized         = 'incremental',
    unique_key           = 'event_id',
    incremental_strategy = 'merge',
    tags                 = ['events', 'incremental']
  )
}}

SELECT
  event_id,
  user_id,
  anonymous_id,
  event_type,
  occurred_at,
  session_id,
  platform,
  properties,
  page_url,
  country
FROM {{ source('analytics', 'events') }}

{% if is_incremental() %}
  WHERE occurred_at > (SELECT MAX(occurred_at) FROM {{ this }})
{% endif %}

{{
  config(
    materialized         = 'incremental',
    incremental_strategy = 'insert_overwrite',
    partition_by         = {'field': 'spend_date', 'data_type': 'date'},
    tags                 = ['marketing', 'incremental']
  )
}}

SELECT
  spend_date,
  channel,
  campaign_id,
  campaign_name,
  SUM(impressions) AS impressions,
  SUM(clicks)      AS clicks,
  SUM(spend_usd)   AS spend_usd,
  SUM(conversions) AS conversions,
  SUM(revenue_usd) AS revenue_usd
FROM {{ source('marketing', 'ad_spend') }}

{% if is_incremental() %}
  WHERE spend_date >= DATE_SUB(CURRENT_DATE(), INTERVAL 3 DAY)
{% endif %}

GROUP BY spend_date, channel, campaign_id, campaign_name

{{
  config(
    materialized = 'table',
    partition_by = {
      'field'       : 'created_at',
      'data_type'   : 'timestamp',
      'granularity' : 'day'
    },
    cluster_by   = ['customer_id', 'status'],
    tags         = ['mart', 'orders', 'optimised']
  )
}}

SELECT
  order_id,
  customer_id,
  created_at,
  DATE(created_at)  AS order_date,
  amount_usd,
  status,
  shipping_country
FROM {{ ref('stg_orders') }}
WHERE status IS NOT NULL

{{
  config(
    materialized = 'table',
    tags         = ['mart', 'keys']
