}}

SELECT
  {{ dbt_utils.generate_surrogate_key(['order_id', 'customer_id']) }} AS surrogate_key,
  order_id,
  customer_id,
  created_at,
  amount_usd,
  status
FROM {{ ref('stg_orders') }}

